import type { PolarDataPoint } from './polar-plot.models';

export type CsvLabelMode = 'datetime' | 'speed' | 'none';

export interface CsvPolarPoint extends PolarDataPoint {
  labelText?: string;
}

/**
 * transformCsvToPolarPoints()
 *
 * Converts the compact tuple array directly to PolarDataPoint[].
 * Phase is already in degrees — no radians conversion applied.
 * O(n) — no join required (amp + phase are co-located per row).
 *
 * @param data      The csvPolarData tuple array
 * @param labelMode 'datetime' | 'speed' | 'none'
 */
export function transformCsvToPolarPoints(
  data: readonly [number, number, number, string][],
  labelMode: CsvLabelMode = 'datetime',
): CsvPolarPoint[] {
  return data.map(([amp, phase, speed, ts]) => ({
    amplitudeValue: amp,
    phaseValue: phase,  // already degrees — used directly by polar plot
    labelText:
      labelMode === 'speed'    ? `${speed} rpm` :
      labelMode === 'datetime' ? ts :
      undefined,
  }));
}

